update.value:


	UPDATE IBS.T5_EMP_GDQ_OR_GZ
	SET	
		EMP_ID=@{EMP_ID}
	   ,EMP_NM=@{EMP_NM}	
	   ,ORG_ID=@{ORG_ID}
	   ,ORG_NM=@{ORG_NM}
	   ,BRANCH_ORG_ID=@{BRANCH_ORG_ID}
	   ,BRANCH_ORG_NM=@{BRANCH_ORG_NM}
	   ,GDQ_STDT=@{GDQ_STDT}
	   ,GDQ_ENDDT=@{GDQ_ENDDT}

	   ,PSTN_TYPE=@{PSTN_TYPE}
	   ,PSTN_TYPE_NM=@{PSTN_TYPE_NM}
	   ,SUB_PSTN_TYPE=@{SUB_PSTN_TYPE}
	   ,SUB_PSTN_TYPE_NM=@{SUB_PSTN_TYPE_NM}
       ,MODIFY_PEOPLE=#{user_id}
       ,MODIFY_TIME=#{current_time}
       ,MODIFY_IP=#{ip}
       ,STATUS='0'
	WHERE EXAM_YEAR=@{EXAM_YEAR__old}
	AND EXAM_Q=@{EXAM_Q__old}
	AND EMP_ID=@{EMP_ID__old}
	AND coalesce(DEL_FLAG,0)<>1
	AND EMP_TYPE='过渡期'
	;

insert.value:

   INSERT INTO IBS.T5_EMP_GDQ_OR_GZ (
		    EXAM_YEAR
		   ,EXAM_Q
		   ,EMP_ID
		   ,EMP_NM	
		   ,ORG_ID
		   ,ORG_NM
		   ,BRANCH_ORG_ID
		   ,BRANCH_ORG_NM
		   ,GDQ_STDT
		   ,GDQ_ENDDT   
		   ,PSTN_TYPE
		   ,PSTN_TYPE_NM
		   ,SUB_PSTN_TYPE
		   ,SUB_PSTN_TYPE_NM
		   ,MODIFY_PEOPLE
		   ,MODIFY_TIME
		   ,MODIFY_IP
		   ,EMP_TYPE
		   ,DEL_FLAG
		   ,STATUS
		   ,MEASURE_DT
		 )
		values(
		  @{EXAM_YEAR} 
		  ,@{EXAM_Q}
		  ,@{EMP_ID}
		  ,@{EMP_NM}
		  ,@{ORG_ID}
		  ,@{ORG_NM}
		  ,@{BRANCH_ORG_ID} 
		  ,@{BRANCH_ORG_NM} 
		  ,@{GDQ_STDT}
		  ,@{GDQ_ENDDT}
		  ,@{PSTN_TYPE}
		  ,@{PSTN_TYPE_NM} 
		  ,@{SUB_PSTN_TYPE}
		  ,@{SUB_PSTN_TYPE_NM}
		  ,#{user_id}
		  ,#{current_time}
		  ,#{ip}
		  ,'过渡期'
		  ,'0' 
		  ,'0'
		  ,CONCAT(@{EXAM_YEAR},'-',(case @{EXAM_Q} when '01' then '03-31' when '02' then '06-30' when '03' then '09-30' when '04' then '12-31' else '01-01' end))
		);

sql.delete:






DELETE FROM IBS.T5_EMP_GDQ_OR_GZ
WHERE EXAM_YEAR=@{EXAM_YEAR__old}
AND EXAM_Q=@{EXAM_Q__old}
AND EMP_ID=@{EMP_ID__old}
AND coalesce(DEL_FLAG,'0')='1'
AND EMP_TYPE='过渡期'
;		
UPDATE IBS.T5_EMP_GDQ_OR_GZ
SET DEL_FLAG='1'
	,MODIFY_PEOPLE=#{user_id}
	,MODIFY_TIME=#{current_time}
	,MODIFY_IP=#{ip}
WHERE EXAM_YEAR=@{EXAM_YEAR__old}
AND EXAM_Q=@{EXAM_Q__old}
AND EMP_ID=@{EMP_ID__old}
AND coalesce(DEL_FLAG,'0')='0'
AND EMP_TYPE='过渡期'
AND STATUS not in ('1','3')
;

format.value:

if(STATUS.equals("0")) STATUS="已保存";
if(STATUS.equals("1")) STATUS="已提交";
if(STATUS.equals("2")) STATUS="分行有权人审核不通过";
if(STATUS.equals("3")) STATUS="分行有权人审核审核通过";

