button.value:

UPDATE IBS.T5_EMP_GDQ_OR_GZ
SET STATUS='3'
	, VERIFY_TIME=#{current_time}
	, VERIFY_PEOPLE=#{user_id} 
	, VERIFY_IP= #{userIp}   
	, REMARK='审批通过'                        					
WHERE EXAM_YEAR=@{param_year}
AND EXAM_Q=@{param_examQ}
AND EMP_ID=@{param_empId}
AND DEL_FLAG='0'
AND STATUS='1'
;
UPDATE IBS.T5_EMP_BZJX
set EMP_TYPE='过渡期'
,MODIFY_PEOPLE=#{user_id}
,MODIFY_TIME=#{current_time}
,MODIFY_IP=#{userIp}
where EXAM_YEAR=@{param_year}
AND EXAM_Q=@{param_examQ}
AND EMP_ID=@{param_empId}
;

format.value:



String btnsh_ztCls="cls-button2";
String btnUnsh_ztCls="cls-button2";

String btnsh_ztEvent="if(confirm('提交后数据将不能修改，是否确认提交?')){invokeComponentSqlActionButton('emp_gdq_ver','select','button1',{param_year:'"+EXAM_YEAR+"',param_examQ:'"+EXAM_Q+"',param_empId:'"+EMP_ID+"'},true,refreshPage)}";
String btnUnsh_ztEvent="wx_winpage('ShowReport.wx?PAGEID=emp_gdq_verNo&EXAM_YEAR="+EXAM_YEAR+"&EXAM_Q="+EXAM_Q+"&EMP_ID="+EMP_ID+"',{width:550,height:350});art.dialog.close();";



if(STATUS.equals("3")){
	sh_zt_btn="";
}else{
	sh_zt_btn="<input type=\"button\" class=\""+btnsh_ztCls+"\" value=\"通过\" onclick=\""+btnsh_ztEvent+"\">";
	sh_zt_btn=sh_zt_btn+"<input type=\"button\" class=\""+btnUnsh_ztCls+"\" value=\"不通过\"   onclick=\""+btnUnsh_ztEvent+"\">";
}

if(STATUS.equals("0")) STATUS="保存";
if(STATUS.equals("1")) STATUS="等待审核";
if(STATUS.equals("2")) STATUS="审核不通过";
if(STATUS.equals("3")) STATUS="审核通过";

